  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { jsonError } from "../http/response";
  3→import type { AgentType } from "../chat/tools/types";
  4→import { createJwtValidator, type BrainTokenClaims } from "./token-validation";
  5→import type { McpAuthResult } from "./types";
  6→
  7→type WorkspaceRow = {
  8→  id: RecordId<"workspace", string>;
  9→  name: string;
 10→};
 11→
 12→const VALID_AGENT_TYPES = new Set<AgentType>([
 13→  "code_agent", "architect", "management", "design_partner", "observer",
 14→]);
 15→
 16→const validatorsByIssuer = new Map<string, (token: string) => Promise<BrainTokenClaims>>();
 17→
 18→/**
 19→ * Authenticate an MCP request via OAuth 2.1 JWT Bearer token.
 20→ * Validates the JWT signature via JWKS, extracts claims, and verifies workspace access.
 21→ * Returns auth context on success, or an error Response.
 22→ */
 23→export async function authenticateMcpRequest(
 24→  request: Request,
 25→  workspaceId: string,
 26→  surreal: Surreal,
 27→  issuerUrl: string,
 28→): Promise<McpAuthResult | Response> {
 29→  const authHeader = request.headers.get("authorization");
 30→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 31→    return jsonError("missing or invalid Authorization header", 401);
 32→  }
 33→
 34→  const token = authHeader.slice(7);
 35→  if (!token) {
 36→    return jsonError("empty Bearer token", 401);
 37→  }
 38→
 39→  // Get or create a JWT validator for this issuer URL (safe for concurrent test suites)
 40→  let validateToken = validatorsByIssuer.get(issuerUrl);
 41→  if (!validateToken) {
 42→    validateToken = createJwtValidator(issuerUrl);
 43→    validatorsByIssuer.set(issuerUrl, validateToken);
 44→  }
 45→
 46→  let claims: BrainTokenClaims;
 47→  try {
 48→    claims = await validateToken(token);
 49→  } catch (err) {
 50→    const detail = err instanceof Error ? err.message : String(err);
 51→    console.error(`[MCP Auth] JWT validation failed: ${detail}`);
 52→    return jsonError("invalid or expired token", 401);
 53→  }
 54→
 55→  // Extract person from sub claim (better-auth user model is person)
 56→  const personId = claims.sub;
 57→  if (!personId) {
 58→    return jsonError("token missing sub claim", 401);
 59→  }
 60→
 61→  // Extract workspace from custom claim or verify against requested workspace
 62→  const claimedWorkspace = claims["urn:brain:workspace"];
 63→  if (claimedWorkspace && claimedWorkspace !== workspaceId) {
 64→    return jsonError("token workspace does not match requested workspace", 403);
 65→  }
 66→
 67→  // Verify workspace exists
 68→  const workspaceRecord = new RecordId("workspace", workspaceId);
 69→  const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
 70→  if (!workspace) {
 71→    return jsonError("workspace not found", 404);
 72→  }
 73→
 74→  // Resolve identity from person via spoke edge
 75→  const personRecord = new RecordId("person", personId);
 76→  const [identityRows] = await surreal.query<[Array<RecordId<"identity", string>>]>(
 77→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 78→    { person: personRecord },
 79→  );
 80→  const identityRecord = identityRows[0];
 81→  if (!identityRecord) {
 82→    return jsonError("identity not found for token owner", 403);
 83→  }
 84→
 85→  // If no workspace claim in token, verify membership via DB
 86→  if (!claimedWorkspace) {
 87→    const [memberRows] = await surreal.query<[Array<{ role: string }>]>(
 88→      `SELECT role FROM member_of WHERE in = $identity AND out = $ws LIMIT 1;`,
 89→      { identity: identityRecord, ws: workspaceRecord },
 90→    );
 91→    if (!memberRows || memberRows.length === 0) {
 92→      return jsonError("token owner is not a member of this workspace", 403);
 93→    }
 94→  }
 95→
 96→  // Extract scopes from token
 97→  const scopeString = claims.scope ?? "";
 98→  const scopes = new Set(scopeString.split(" ").filter(Boolean));
 99→
100→  // Agent type from header or from token claim
101→  const claimedAgentType = claims["urn:brain:agent_type"];
102→  const rawAgentType = request.headers.get("x-agent-type") ?? claimedAgentType ?? "code_agent";
103→  if (!VALID_AGENT_TYPES.has(rawAgentType as AgentType)) {
104→    return jsonError(`invalid agent type: ${rawAgentType}`, 400);
105→  }
106→
107→  return {
108→    workspaceRecord,
109→    workspaceName: workspace.name,
110→    agentType: rawAgentType as AgentType,
111→    identityRecord,
112→    scopes,
113→    humanPresent: false as const,
114→  };
115→}
