  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
