261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const sessionId = request.params.sessionId;
272→
273→    if (!sessionId) {
274→      return jsonError("sessionId is required", 400);
275→    }
276→
277→    const streamId = `stream-${sessionId}`;
278→    return deps.sseRegistry.handleStreamRequest(streamId);
279→  };
280→
281→  return { stream };
282→}
