284→// ---------------------------------------------------------------------------
285→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
286→// ---------------------------------------------------------------------------
287→
288→export type OrchestratorWiringDeps = {
289→  surreal: import("surrealdb").Surreal;
290→  shellExec: import("./worktree-manager").ShellExec;
291→  brainBaseUrl: string;
292→  sseRegistry?: SseRegistry;
293→  queryFn: import("./spawn-agent").QueryFn;
294→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
295→};
296→
297→export function wireOrchestratorRoutes(
298→  wiringDeps: OrchestratorWiringDeps,
299→): {
300→  assign: RouteHandler;
301→  status: RouteHandler;
302→  accept: RouteHandler;
303→  abort: RouteHandler;
304→  review: RouteHandler;
305→  reject: RouteHandler;
306→  prompt: RouteHandler;
307→  stream?: RouteHandler;
308→} {
309→  // Workspace access guard — resolves user from session cookie, checks membership
310→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
311→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
312→    if (!session?.user?.id) {
313→      return jsonError("authentication required", 401);
314→    }
315→    const { RecordId } = await import("surrealdb");
316→    const personRecord = new RecordId("person", session.user.id);
317→    const workspaceRecord = new RecordId("workspace", workspaceId);
318→    // member_of is identity->workspace; resolve person->identity via identity_person
319→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
320→      `SELECT role FROM member_of WHERE in IN $person<-identity_person<-identity AND out = $ws LIMIT 1;`,
321→      { person: personRecord, ws: workspaceRecord },
322→    );
323→    if (!memberRows || memberRows.length === 0) {
324→      return jsonError("not a member of this workspace", 403);
325→    }
326→    return undefined;
327→  };
328→
329→  // Lazy imports to keep module boundary clean
330→  const lifecycleImport = import("./session-lifecycle");
331→  const queriesImport = import("../mcp/mcp-queries");
332→  const guardImport = import("./assignment-guard");
333→  const stallDetectorImport = import("./stall-detector");
334→
335→  // Helper: resolve repo_path from workspace record
336→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
337→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
338→      `SELECT repo_path FROM $ws;`,
339→      { ws: workspaceRecord },
340→    );
341→    const repoPath = rows[0]?.repo_path;
342→    if (!repoPath) {
343→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
344→    }
345→    return repoPath;
346→  };
347→
348→  // Use mock spawn for acceptance tests, production spawn otherwise
349→  const spawnAgentImport = process.env.ORCHESTRATOR_MOCK_AGENT === "true"
350→    ? Promise.resolve({
351→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
352→          () => ({
353→            messages: (async function* () {})(),
354→            abort: () => {},
355→          }),
356→      })
357→    : import("./spawn-agent");
358→
359→  const routeDeps: OrchestratorRouteDeps = {
360→    createSession: async (workspaceId, taskId, authToken) => {
361→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
362→        lifecycleImport,
363→        queriesImport,
364→        guardImport,
365→        spawnAgentImport,
366→        stallDetectorImport,
367→      ]);
368→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
369→      const result = await lifecycle.createOrchestratorSession({
370→        surreal: wiringDeps.surreal,
371→        shellExec: wiringDeps.shellExec,
372→        brainBaseUrl: wiringDeps.brainBaseUrl,
373→        workspaceId,
374→        taskId,
375→        authToken,
376→        validateAssignment: guard.validateAssignment,
377→        createAgentSession: queries.createAgentSession,
378→        spawnAgent,
379→      });
380→
381→      // Wire SSE stream + event iteration on success
382→      if (result.ok && wiringDeps.sseRegistry) {
383→        const { agentSessionId, streamId } = result.value;
384→        wiringDeps.sseRegistry.registerMessage(streamId);
385→
386→        const handle = lifecycle.getHandle(agentSessionId);
387→        if (handle) {
388→          const { RecordId } = await import("surrealdb");
389→          lifecycle.startEventIteration(
390→            {
391→              emitEvent: wiringDeps.sseRegistry.emitEvent,
392→              updateSessionStatus: async (sid, status, error) => {
393→                const rec = new RecordId("agent_session", sid);
394→                await wiringDeps.surreal.update(rec).merge({
395→                  orchestrator_status: status,
396→                  ...(error !== undefined ? { error } : {}),
397→                });
398→              },
399→              updateLastEventAt: async (sid) => {
400→                const rec = new RecordId("agent_session", sid);
401→                await wiringDeps.surreal.update(rec).merge({
402→                  last_event_at: new Date(),
403→                });
404→              },
405→              getSessionStatus: async (sid) => {
406→                const rec = new RecordId("agent_session", sid);
407→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
408→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
409→              },
410→              startStallDetector: (sid, stId) =>
411→                stallDetector.startStallDetector(
412→                  {
413→                    abortSession: async (abortSid) => {
414→                      const abortResult = await lifecycle.abortOrchestratorSession({
415→                        surreal: wiringDeps.surreal,
416→                        shellExec: wiringDeps.shellExec,
417→                        resolveRepoRoot,
418→                        sessionId: abortSid,
419→                        endAgentSession: queries.endAgentSession,
420→                      });
421→                      return abortResult;
422→                    },
423→                    createObservation: async () => {},
424→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
425→                  },
426→                  stallDetector.DEFAULT_STALL_CONFIG,
427→                  sid,
428→                  stId,
429→                ),
430→            },
431→            handle.messages,
432→            streamId,
433→            agentSessionId,
434→          );
435→        }
436→      }
437→
438→      return result;
439→    },
440→
441→    getSessionStatus: async (sessionId) => {
442→      const lifecycle = await lifecycleImport;
443→      return lifecycle.getOrchestratorSessionStatus({
444→        surreal: wiringDeps.surreal,
445→        sessionId,
446→      });
447→    },
448→
449→    abortSession: async (sessionId) => {
450→      const [lifecycle, queries] = await Promise.all([
451→        lifecycleImport,
452→        queriesImport,
453→      ]);
454→      return lifecycle.abortOrchestratorSession({
455→        surreal: wiringDeps.surreal,
456→        shellExec: wiringDeps.shellExec,
457→        resolveRepoRoot,
458→        sessionId,
459→        endAgentSession: queries.endAgentSession,
460→      });
461→    },
462→
463→    acceptSession: async (sessionId, summary) => {
464→      const [lifecycle, queries] = await Promise.all([
465→        lifecycleImport,
466→        queriesImport,
467→      ]);
468→      return lifecycle.acceptOrchestratorSession({
469→        surreal: wiringDeps.surreal,
470→        sessionId,
471→        summary,
472→        endAgentSession: queries.endAgentSession,
473→      });
474→    },
475→
476→    getReview: async (sessionId) => {
477→      const [lifecycle, worktreeManager] = await Promise.all([
478→        lifecycleImport,
479→        import("./worktree-manager"),
480→      ]);
481→      return lifecycle.getOrchestratorReview({
482→        surreal: wiringDeps.surreal,
483→        sessionId,
484→        resolveRepoRoot,
485→        getDiff: (repoRoot: string, branchName: string) =>
486→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
487→        getTaskTitle: async (taskId: string) => {
488→          const { RecordId } = await import("surrealdb");
489→          const taskRecord = new RecordId("task", taskId);
490→          const rows = (await wiringDeps.surreal.query(
491→            `SELECT title FROM $task;`,
492→            { task: taskRecord },
493→          )) as Array<Array<{ title: string }>>;
494→          return rows[0]?.[0]?.title ?? "";
495→        },
496→      });
497→    },
498→
499→    rejectSession: async (sessionId, feedback) => {
500→      const lifecycle = await lifecycleImport;
501→      return lifecycle.rejectOrchestratorSession({
502→        surreal: wiringDeps.surreal,
503→        sessionId,
504→        feedback,
505→      });
506→    },
507→
508→    sendPrompt: async (sessionId, text) => {
509→      const lifecycle = await lifecycleImport;
510→      return lifecycle.sendSessionPrompt({
511→        surreal: wiringDeps.surreal,
512→        sessionId,
513→        text,
514→      });
515→    },
516→  };
517→
518→  const handlers = createOrchestratorRouteHandlers(routeDeps);
519→
520→  // Wrap handler with workspace access check
521→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
522→    const workspaceId = request.params.workspaceId;
523→    if (workspaceId) {
524→      const accessError = await validateWorkspaceAccess(request, workspaceId);
525→      if (accessError) return accessError;
526→    }
527→    return handler(request);
528→  };
529→
530→  const streamHandler = wiringDeps.sseRegistry
531→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
532→    : undefined;
533→
534→  return {
535→    assign: withRequestLogging("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
536→    status: withRequestLogging("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
537→    accept: withRequestLogging("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
538→    abort: withRequestLogging("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
539→    review: withRequestLogging("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
540→    reject: withRequestLogging("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
541→    prompt: withRequestLogging("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
542→    ...(streamHandler
543→      ? { stream: withRequestLogging("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
544→      : {}),
545→  };
546→}
