169→    status: options.status ?? "ready",
170→    created_at: new Date(),
171→    updated_at: new Date(),
172→    workspace: workspaceRecord,
173→  };
174→
175→  if (options.projectId) {
176→    const projectRecord = new RecordId("project", options.projectId);
177→    await surreal.query(
178→      `CREATE $task CONTENT $content;
179→       RELATE $task->belongs_to->$project SET added_at = time::now();`,
180→      { task: taskRecord, content: { ...content }, project: projectRecord },
181→    );
182→  } else {
183→    await surreal.query(`CREATE $task CONTENT $content;`, {
184→      task: taskRecord,
185→      content,
186→    });
187→  }
188→
189→  return { taskId, taskRecord };
190→}
