237→// ---------------------------------------------------------------------------
238→// SSE Helpers
239→// ---------------------------------------------------------------------------
240→
241→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
242→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
243→  if (!response.ok || !response.body) {
244→    throw new Error(`Failed to open SSE stream (${response.status})`);
245→  }
246→
247→  const reader = response.body.getReader();
248→  const decoder = new TextDecoder();
249→  const events: T[] = [];
250→  let buffer = "";
251→
252→  const timeout = setTimeout(() => {
253→    void reader.cancel();
254→  }, timeoutMs);
255→
256→  try {
257→    while (true) {
258→      const { value, done } = await reader.read();
259→      if (done) {
260→        break;
261→      }
262→
263→      buffer += decoder.decode(value, { stream: true });
264→      const segments = buffer.split("\n\n");
265→      buffer = segments.pop() ?? "";
266→
267→      for (const segment of segments) {
268→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
269→        if (!dataLine) {
270→          continue;
271→        }
272→
273→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
274→        events.push(event);
275→
276→        if (event.type === "error") {
277→          const errorText = (event as { error?: string }).error;
278→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
279→        }
280→
281→        if (event.type === "done") {
282→          return events;
283→        }
284→      }
285→    }
286→  } finally {
287→    clearTimeout(timeout);
288→    reader.releaseLock();
289→  }
290→
291→  return events;
292→}
